declare enum SCREENS {
    SMALL = "sm",// 0 - 767px - Mobile
    MEDIUM = "md",// 768 - 1023px - Tablet
    LARGE = "lg",// 1024 - 1279px - Laptop
    XLARGE = "xl",// 1280 - 1919px - Desktop
    XXLARGE = "xxl"
}
declare const getScreenVariant: () => SCREENS.MEDIUM | SCREENS.LARGE | SCREENS.XLARGE | SCREENS.XXLARGE;
export { getScreenVariant, SCREENS };
